import { env } from "@/env";
import { logger } from "@/lib/logger";

// Lazy-loaded S3 client and SDK types
let s3Client: InstanceType<typeof import("@aws-sdk/client-s3").S3Client> | null = null;
let isInitialized = false;

// Cache for dynamically imported modules
let S3ClientClass: typeof import("@aws-sdk/client-s3").S3Client | null = null;
let PutObjectCommandClass: typeof import("@aws-sdk/client-s3").PutObjectCommand | null = null;
let DeleteObjectCommandClass: typeof import("@aws-sdk/client-s3").DeleteObjectCommand | null = null;
let getSignedUrlFn: typeof import("@aws-sdk/s3-request-presigner").getSignedUrl | null = null;

/**
 * Lazily loads the AWS SDK modules to prevent Turbopack bundling issues.
 * The SDK is only loaded when S3 functionality is actually used.
 */
async function loadAwsSdk() {
  if (!S3ClientClass) {
    const s3Module = await import("@aws-sdk/client-s3");
    S3ClientClass = s3Module.S3Client;
    PutObjectCommandClass = s3Module.PutObjectCommand;
    DeleteObjectCommandClass = s3Module.DeleteObjectCommand;
  }
  if (!getSignedUrlFn) {
    const presignerModule = await import("@aws-sdk/s3-request-presigner");
    getSignedUrlFn = presignerModule.getSignedUrl;
  }
}

/**
 * Initializes the S3 client if the feature is enabled and credentials are available.
 * Uses dynamic imports to avoid Turbopack bundling issues.
 */
async function initializeS3Client() {
  if (isInitialized) return s3Client;

  if (!env.NEXT_PUBLIC_FEATURE_S3_ENABLED) {
    isInitialized = true;
    return null;
  }

  if (!env.AWS_REGION || !env.AWS_ACCESS_KEY_ID || !env.AWS_SECRET_ACCESS_KEY) {
    logger.error("❌ S3 feature is enabled, but required AWS credentials or region are missing.");
    isInitialized = true;
    return null;
  }

  try {
    await loadAwsSdk();

    if (!S3ClientClass) {
      throw new Error("Failed to load S3Client class");
    }

    s3Client = new S3ClientClass({
      region: env.AWS_REGION,
      credentials: {
        accessKeyId: env.AWS_ACCESS_KEY_ID,
        secretAccessKey: env.AWS_SECRET_ACCESS_KEY,
      },
    });

    logger.info("✅ S3 Client Initialized");
    isInitialized = true;
    return s3Client;
  } catch (error) {
    logger.error("❌ Failed to initialize S3 client:", error);
    isInitialized = true;
    return null;
  }
}

/**
 * Gets the S3 client, initializing it if necessary.
 */
async function getS3Client() {
  if (!isInitialized) {
    await initializeS3Client();
  }
  return s3Client;
}

/**
 * Generates a presigned URL for uploading a file to S3.
 * Throws an error if S3 is not configured or enabled.
 */
export async function generatePresignedUrl(fileName: string, contentType: string) {
  const client = await getS3Client();
  if (!client) {
    logger.error("Attempted to generate presigned URL but S3 is disabled or not configured.");
    throw new Error("S3 storage is not enabled or configured.");
  }

  await loadAwsSdk();
  if (!PutObjectCommandClass || !getSignedUrlFn) {
    throw new Error("S3 SDK not available");
  }

  const command = new PutObjectCommandClass({
    Bucket: env.AWS_BUCKET_NAME,
    Key: fileName,
    ContentType: contentType,
  });

  try {
    const signedUrl = await getSignedUrlFn(client, command, { expiresIn: 3600 });
    return signedUrl;
  } catch (error) {
    logger.error("Error generating presigned URL", { error, fileName, contentType });
    throw new Error("Failed to generate presigned URL for S3");
  }
}

/**
 * Deletes a file from S3.
 * Throws an error if S3 is not configured or enabled.
 */
export const deleteFromS3 = async (fileName: string): Promise<void> => {
  const client = await getS3Client();
  if (!client) {
    logger.error("Attempted to delete from S3 but S3 is disabled or not configured.");
    throw new Error("S3 storage is not enabled or configured.");
  }

  try {
    await loadAwsSdk();
    if (!DeleteObjectCommandClass) {
      throw new Error("S3 SDK not available");
    }

    await client.send(
      new DeleteObjectCommandClass({
        Bucket: env.AWS_BUCKET_NAME,
        Key: fileName,
      })
    );
  } catch (error) {
    logger.error("Error deleting file from S3", { error, fileName });
    throw new Error("Failed to delete file from S3");
  }
};

import { logger } from "@/lib/logger";
import { type FileSchemaType, fileSchema } from "@/server/actions/schemas";
import { deleteFromS3, generatePresignedUrl } from "@/server/services/s3";

export const uploadFile = async (
  file: FileSchemaType
): Promise<{ fileName: string; url: string }> => {
  const validatedFile = fileSchema.parse(file);

  try {
    const fileName = `${Date.now()}-${validatedFile.name}`;
    const signedUrl = await generatePresignedUrl(fileName, validatedFile.type);

    if (!signedUrl) {
      throw new Error(`Failed to generate presigned URL for file: ${fileName}`);
    }

    const response = await fetch(signedUrl, {
      method: "PUT",
      body: validatedFile,
      headers: {
        "Content-Type": validatedFile.type,
      },
    });

    if (!response.ok) {
      throw new Error(`Failed to upload file: ${validatedFile.name}`);
    }

    logger.info(`File uploaded successfully: ${fileName}`);
    const s3Url = signedUrl.split("?")[0]; // This gets the S3 URL without the query parameters
    return { fileName, url: s3Url ?? signedUrl };
  } catch (error) {
    // Friendly error message
    const errorMessage = `Error uploading file: ${validatedFile.name}`;
    logger.error(errorMessage, error);
    throw new Error(errorMessage);
  }
};

export const deleteFile = async (fileName: string): Promise<void> => {
  try {
    await deleteFromS3(fileName);
    logger.info(`File deleted successfully: ${fileName}`);
  } catch (error) {
    const errorMessage = `Error deleting file: ${fileName}`;
    logger.error(errorMessage, error);
    throw new Error(errorMessage);
  }
};

"use server";

import { revalidateTag } from "next/cache";
import { logger } from "@/lib/logger";
import { fileSchema } from "@/server/actions/schemas";
import { auth } from "@/server/auth";
import { deleteFile, uploadFile } from "@/server/services/file";
import { userService } from "@/server/services/user-service";

export const uploadFileAction = async (
  formData: FormData
): Promise<{ fileName: string; fileId: number | undefined }> => {
  const session = await auth();
  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }

  const file = formData.get("file") as File;
  if (!file) {
    throw new Error("No file provided");
  }

  const validatedFile = fileSchema.parse(file);
  const { fileName, url } = await uploadFile(validatedFile);

  // Log the file name and URL
  logger.info(`File uploaded - Name: ${fileName}, URL: ${url}`);

  // Add the file to the user's profile
  const userFile = await userService.addUserFile(session.user.id, {
    title: fileName,
    location: url,
  });
  revalidateTag("files", "max");
  if (!userFile) {
    throw new Error("Failed to create user file");
  }
  return { fileName, fileId: userFile.id };
};

export async function deleteFileAction({
  fileId,
  fileName,
}: {
  fileId: number;
  fileName: string;
}): Promise<void> {
  const session = await auth();
  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }

  try {
    await userService.deleteUserFile(session.user.id, fileId);
    await deleteFile(fileName);
    // Remove the file from the user's profile
    revalidateTag("files", "max");

    logger.info(`File deleted successfully: ${fileId}`);
  } catch (error) {
    logger.error("Error deleting file", { error, fileId });
    throw new Error("Failed to delete file");
  }
}

"use client";

import { AnimatePresence, motion } from "framer-motion";
import { File, Trash2, Upload } from "lucide-react";
import type React from "react";
import { type DragEvent, useEffect, useRef, useState } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { ALLOWED_FILE_TYPES, FILE_UPLOAD_MAX_SIZE } from "@/config/file";
import { env } from "@/env";
import { logger } from "@/lib/logger";
import { deleteFileAction, uploadFileAction } from "@/server/actions/file";

interface FileWithPreview {
  id: string;
  file: File;
  preview: string;
  progress: number;
  status: "pending" | "uploading" | "completed" | "error";
  uploadedName?: string;
  fileId?: number;
}

const enabled = env.NEXT_PUBLIC_FEATURE_FILE_UPLOAD_ENABLED;

export function FileDropzone() {
  const [files, setFiles] = useState<FileWithPreview[]>([]);
  const [isDragActive, setIsDragActive] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const progressIntervalRef = useRef<Record<string, NodeJS.Timeout>>({});

  const isValidFile = (file: File) => {
    if (!ALLOWED_FILE_TYPES.includes(file.type)) {
      toast.error(`${file.name} is not an allowed file type.`);
      return false;
    }
    if (file.size > FILE_UPLOAD_MAX_SIZE) {
      toast.error(`${file.name} exceeds the size limit.`);
      return false;
    }
    return true;
  };

  const uploadFile = async (fileWithPreview: FileWithPreview) => {
    if (!env.NEXT_PUBLIC_FEATURE_FILE_UPLOAD_ENABLED) {
      toast.error("File uploads are currently disabled.");
      return {
        success: false,
        file: fileWithPreview,
        error: "File uploads are disabled.",
      };
    }

    const formData = new FormData();
    formData.append("file", fileWithPreview.file);

    try {
      // Set initial uploading state
      setFiles((prev) =>
        prev.map((f) =>
          f.id === fileWithPreview.id ? { ...f, status: "uploading", progress: 10 } : f
        )
      );

      // Start progress simulation
      if (progressIntervalRef.current[fileWithPreview.id]) {
        clearInterval(progressIntervalRef.current[fileWithPreview.id]);
      }
      progressIntervalRef.current[fileWithPreview.id] = setInterval(() => {
        setFiles((prev) => {
          return prev.map((f) => {
            if (f.id === fileWithPreview.id && f.status === "uploading") {
              const newProgress = Math.min(f.progress + 15, 90);
              return { ...f, progress: newProgress };
            }
            return f;
          });
        });
      }, 300);

      // Perform the actual upload
      const { fileName, fileId } = await uploadFileAction(formData);

      // Clear the interval
      clearInterval(progressIntervalRef.current[fileWithPreview.id]);
      delete progressIntervalRef.current[fileWithPreview.id];

      if (fileName) {
        // Update state to completed
        setFiles((prev) =>
          prev.map((f) => {
            if (f.id === fileWithPreview.id) {
              return {
                ...f,
                status: "completed",
                progress: 100,
                uploadedName: fileName,
                fileId,
              };
            }
            return f;
          })
        );

        logger.info(`File uploaded successfully: ${fileName}`);
        return { success: true, file: fileWithPreview };
      }
      return { success: false, file: fileWithPreview, error: "Upload failed" };
    } catch (error) {
      clearInterval(progressIntervalRef.current[fileWithPreview.id]);

      setFiles((prev) =>
        prev.map((f) => (f.id === fileWithPreview.id ? { ...f, status: "error", progress: 0 } : f))
      );

      return {
        success: false,
        file: fileWithPreview,
        error: `Error uploading file: ${fileWithPreview.file.name}`,
      };
    }
  };

  const handleFiles = (fileList: File[]) => {
    if (!enabled) return;
    const validFiles = fileList.filter(isValidFile);

    const newFiles = validFiles.map((file) => ({
      id: crypto.randomUUID(),
      file,
      preview: file.type.startsWith("image/") ? URL.createObjectURL(file) : "",
      progress: 0,
      status: "pending" as const,
    }));

    setFiles((prevFiles) => [...prevFiles, ...newFiles]);
  };

  // Effect to handle uploads of pending files
  useEffect(() => {
    const pendingFiles = files.filter((file) => file.status === "pending");

    if (pendingFiles.length === 0) {
      return;
    }

    void (async () => {
      const results = await Promise.all(pendingFiles.map(uploadFile));

      // Handle success/error notifications
      const successful = results.filter((r) => r.success);
      const failed = results.filter((r) => !r.success);

      for (const result of successful) {
        if (successful.length === 1) {
          toast.success(`Successfully uploaded ${result.file.file.name}`);
        } else {
          toast.success(`Successfully uploaded ${successful.length} files`);
          break;
        }
      }

      for (const result of failed) {
        if (result.error) {
          toast.error(result.error);
          logger.error(result.error);
        }
      }
    })();
  }, [files, enabled]);

  // Cleanup effect
  useEffect(() => {
    return () => {
      // Clear all intervals
      for (const intervalId of Object.values(progressIntervalRef.current)) {
        clearInterval(intervalId);
      }
      // Clear all previews
      for (const file of files) {
        if (file.preview) {
          URL.revokeObjectURL(file.preview);
        }
      }
    };
  }, [files]);

  const handleDragEnter = (e: DragEvent<HTMLDivElement>) => {
    if (!enabled) return;
    e.preventDefault();
    e.stopPropagation();
    setIsDragActive(true);
  };

  const handleDragLeave = (e: DragEvent<HTMLDivElement>) => {
    if (!enabled) return;
    e.preventDefault();
    e.stopPropagation();
    setIsDragActive(false);
  };

  const handleDragOver = (e: DragEvent<HTMLDivElement>) => {
    if (!enabled) return;
    e.preventDefault();
    e.stopPropagation();
  };

  const handleDrop = (e: DragEvent<HTMLDivElement>) => {
    if (!enabled) return;
    e.preventDefault();
    e.stopPropagation();
    setIsDragActive(false);

    const droppedFiles = Array.from(e.dataTransfer.files);
    handleFiles(droppedFiles);
  };

  const handleButtonClick = () => {
    if (!enabled) return;
    fileInputRef.current?.click();
  };

  const handleFileInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!enabled) return;
    if (e.target.files) {
      handleFiles(Array.from(e.target.files));
    }
  };

  const handleDeleteFile = (fileToDelete: FileWithPreview) => {
    if (fileToDelete.preview) {
      URL.revokeObjectURL(fileToDelete.preview);
    }
    setFiles((prevFiles) => prevFiles.filter((file) => file.id !== fileToDelete.id));
  };

  const handleDeleteUploadedFile = async (file: FileWithPreview) => {
    if (!enabled) {
      toast.error("File deletion is currently disabled.");
      return;
    }
    if (!file.uploadedName || !file.fileId) {
      return;
    }

    try {
      await deleteFileAction({ fileId: file.fileId, fileName: file.uploadedName });
      toast.success(`Successfully deleted ${file.file.name}`);
      handleDeleteFile(file);
    } catch (error) {
      const errorMessage = `Error deleting file: ${file.file.name}`;
      logger.error(errorMessage, error);
      toast.error(errorMessage);
    }
  };

  const getStatusColor = (status: FileWithPreview["status"]) => {
    switch (status) {
      case "completed":
        return "bg-green-500";
      case "error":
        return "bg-red-500";
      case "uploading":
        return "bg-blue-500";
      default:
        return "bg-neutral-200 dark:bg-neutral-700";
    }
  };

  if (!enabled) {
    return (
      <div className="h-auto w-full p-8 text-center text-neutral-500">
        File uploads are currently disabled.
      </div>
    );
  }

  return (
    <div className="h-auto w-full p-8">
      <motion.div
        className={`relative size-full cursor-pointer rounded-xl border-2 border-dashed p-12 text-center transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ${
          isDragActive
            ? "border-blue-500 bg-blue-500/5"
            : "border-neutral-300 hover:border-neutral-400 dark:border-neutral-700 dark:hover:border-neutral-500"
        }`}
        onClick={handleButtonClick}
        onKeyDown={(e) => {
          if (e.key === "Enter" || e.key === " ") {
            e.preventDefault();
            handleButtonClick();
          }
        }}
        role="button"
        tabIndex={0}
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
        whileHover={{ scale: 1.01 }}
        whileTap={{ scale: 0.98 }}
      >
        <input
          accept={ALLOWED_FILE_TYPES.join(",")}
          className="hidden"
          multiple={true}
          onChange={handleFileInputChange}
          ref={fileInputRef}
          type="file"
        />
        <AnimatePresence>
          {isDragActive ? (
            <motion.div
              animate={{ opacity: 1, y: 0 }}
              className="pointer-events-none select-none"
              exit={{ opacity: 0, y: -10 }}
              initial={{ opacity: 0, y: 10 }}
              transition={{ duration: 0.2 }}
            >
              <Upload className="pointer-events-none mx-auto size-8 select-none text-blue-500" />
              <p className="pointer-events-none mt-2 select-none text-sm text-blue-500">
                Drop files here...
              </p>
            </motion.div>
          ) : (
            <motion.div
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 10 }}
              initial={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.2 }}
            >
              <Upload className="mx-auto size-8 text-neutral-400 dark:text-neutral-500" />
              <p className="mt-2 text-balance text-sm font-medium tracking-tighter text-neutral-400 dark:text-neutral-500">
                Drag and drop files here, or click to select
              </p>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>

      <AnimatePresence>
        {files.length > 0 && (
          <motion.div
            animate={{ opacity: 1, height: "auto" }}
            className="mt-4 space-y-2"
            exit={{ opacity: 0, height: 0 }}
            initial={{ opacity: 0, height: 0 }}
          >
            {files.map((file) => (
              <motion.div
                animate={{ opacity: 1, x: 0 }}
                className="relative flex items-center rounded-lg bg-neutral-400/10 p-1"
                exit={{ opacity: 0, x: 20 }}
                initial={{ opacity: 0, x: -20 }}
                key={file.id}
              >
                <div
                  className={`absolute left-0 top-0 z-0 h-full rounded-lg transition-all duration-300 ${getStatusColor(
                    file.status
                  )}`}
                  style={{ width: `${file.progress}%`, opacity: 0.2 }}
                />

                {file.file.type.startsWith("image/") ? (
                  <img
                    alt={file.file.name}
                    className="mr-2 size-10 rounded object-cover"
                    src={file.preview}
                  />
                ) : (
                  <File className="mr-2 size-10 text-neutral-500" />
                )}
                <div className="z-10 flex flex-1 flex-col">
                  <span className="truncate text-xs tracking-tighter text-neutral-600 dark:text-neutral-400">
                    {file.file.name}
                  </span>
                  <span className="text-xs text-neutral-500">
                    {file.status === "completed"
                      ? "Uploaded"
                      : file.status === "error"
                        ? "Error"
                        : file.status === "uploading"
                          ? "Uploading..."
                          : "Pending"}
                  </span>
                </div>
                <div className="z-10 flex items-center gap-2">
                  {file.status === "completed" ? (
                    <Button
                      variant="destructive"
                      size="sm"
                      onClick={(e) => {
                        e.stopPropagation();
                        void handleDeleteUploadedFile(file);
                      }}
                      className="h-7 px-2"
                    >
                      <Trash2 className="size-4" />
                      <span className="ml-1">Delete</span>
                    </Button>
                  ) : (
                    <button
                      type="button"
                      className="mr-2 rounded-sm text-red-500 transition-colors hover:text-red-600 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDeleteFile(file);
                      }}
                    >
                      <Trash2 className="size-5" />
                      <span className="sr-only">Delete</span>
                    </button>
                  )}
                </div>
              </motion.div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

export default FileDropzone;

